/**
 * Unit tests for lifecycle/sync-session-dispatcher hook
 *
 * Tests sequential execution of sync SessionStart hooks:
 * - analytics-consent-check
 * - prefill-guard
 * - mcp-health-check
 *
 * Covers: systemMessage merging, additionalContext fallback,
 * rules materialization, error isolation, and silent result.
 */

import { describe, it, expect, vi, beforeEach } from 'vitest';
import type { HookInput } from '../../types.js';

// ---------------------------------------------------------------------------
// Mocks
// ---------------------------------------------------------------------------

vi.mock('../../lib/common.js', async () => {
  const actual = await vi.importActual<typeof import('../../lib/common.js')>('../../lib/common.js');
  return {
    ...actual,
    logHook: vi.fn(),
    outputSilentSuccess: vi.fn(() => ({ continue: true, suppressOutput: true })),
    extractContext: vi.fn((result: { hookSpecificOutput?: { additionalContext?: string } }) =>
      result.hookSpecificOutput?.additionalContext ?? null
    ),
    getProjectDir: vi.fn(() => '/test/project'),
  };
});

// Mock consolidated hooks to isolate dispatcher logic
vi.mock('../../lifecycle/analytics-consent-check.js', () => ({
  analyticsConsentCheck: vi.fn(() => ({ continue: true, suppressOutput: true })),
}));

vi.mock('../../lifecycle/prefill-guard.js', () => ({
  prefillGuard: vi.fn(() => ({ continue: true, suppressOutput: true })),
}));

vi.mock('../../lifecycle/mcp-health-check.js', () => ({
  mcpHealthCheck: vi.fn(() => ({ continue: true, suppressOutput: true })),
}));

vi.mock('../../prompt/antipattern-warning.js', () => ({
  materializeAntipatternRules: vi.fn(),
}));

vi.mock('../../lib/analytics.js', () => ({
  appendAnalytics: vi.fn(),
  hashProject: vi.fn(() => 'test_hash'),
}));

import { syncSessionDispatcher } from '../../lifecycle/sync-session-dispatcher.js';
import { appendAnalytics } from '../../lib/analytics.js';
import { analyticsConsentCheck } from '../../lifecycle/analytics-consent-check.js';
import { prefillGuard } from '../../lifecycle/prefill-guard.js';
import { mcpHealthCheck } from '../../lifecycle/mcp-health-check.js';
import { materializeAntipatternRules } from '../../prompt/antipattern-warning.js';
import { logHook } from '../../lib/common.js';
import { createTestContext } from '../fixtures/test-context.js';

// ---------------------------------------------------------------------------
// Helpers
// ---------------------------------------------------------------------------

function createSessionStartInput(overrides: Partial<HookInput> = {}): HookInput {
  return {
    hook_event: 'SessionStart',
    tool_name: '',
    session_id: 'test-session-start-001',
    tool_input: {},
    project_dir: '/test/project',
    ...overrides,
  };
}

function makeSystemMessageResult(msg: string) {
  return { continue: true, systemMessage: msg };
}

function makeContextResult(ctx: string) {
  return {
    continue: true,
    suppressOutput: true,
    hookSpecificOutput: { additionalContext: ctx, hookEventName: 'SessionStart' as never },
  };
}

// ---------------------------------------------------------------------------
// Tests
// ---------------------------------------------------------------------------

let testCtx: ReturnType<typeof createTestContext>;
describe('lifecycle/sync-session-dispatcher', () => {
  beforeEach(() => {
    testCtx = createTestContext();
    vi.resetAllMocks();
    // Re-establish default silent passing implementations after reset
    vi.mocked(analyticsConsentCheck).mockReturnValue({ continue: true, suppressOutput: true });
    vi.mocked(prefillGuard).mockReturnValue({ continue: true, suppressOutput: true });
    vi.mocked(mcpHealthCheck).mockReturnValue({ continue: true, suppressOutput: true });
    vi.mocked(materializeAntipatternRules).mockReturnValue(undefined);
  });

  // -------------------------------------------------------------------------
  // All hooks silent → silent success
  // -------------------------------------------------------------------------

  describe('all hooks silent', () => {
    it('returns silent success when no hooks produce messages', () => {
      const input = createSessionStartInput();
      const result = syncSessionDispatcher(input);

      expect(result.continue).toBe(true);
      expect(result.suppressOutput).toBe(true);
      expect(result.systemMessage).toBeUndefined();
    });

    it('calls all three consolidated hooks', () => {
      const input = createSessionStartInput();
      syncSessionDispatcher(input);

      expect(analyticsConsentCheck).toHaveBeenCalled();
      expect(vi.mocked(analyticsConsentCheck).mock.calls[0][0]).toEqual(input);
      expect(prefillGuard).toHaveBeenCalled();
      expect(vi.mocked(prefillGuard).mock.calls[0][0]).toEqual(input);
      expect(mcpHealthCheck).toHaveBeenCalled();
      expect(vi.mocked(mcpHealthCheck).mock.calls[0][0]).toEqual(input);
    });
  });

  // -------------------------------------------------------------------------
  // systemMessage collection and merging
  // -------------------------------------------------------------------------

  describe('systemMessage merging', () => {
    it('returns single systemMessage when one hook produces it', () => {
      vi.mocked(analyticsConsentCheck).mockReturnValue(
        makeSystemMessageResult('Analytics consent needed.'),
      );

      const input = createSessionStartInput();
      const result = syncSessionDispatcher(input);

      expect(result.systemMessage).toBe('Analytics consent needed.');
    });

    it('merges systemMessages from multiple hooks with newline', () => {
      vi.mocked(analyticsConsentCheck).mockReturnValue(
        makeSystemMessageResult('Consent message.'),
      );
      vi.mocked(prefillGuard).mockReturnValue(
        makeSystemMessageResult('Prefill guard warning.'),
      );

      const input = createSessionStartInput();
      const result = syncSessionDispatcher(input);

      expect(result.systemMessage).toContain('Consent message.');
      expect(result.systemMessage).toContain('Prefill guard warning.');
    });

    it('result has continue: true when systemMessage is present', () => {
      vi.mocked(analyticsConsentCheck).mockReturnValue(
        makeSystemMessageResult('Something to say.'),
      );

      const input = createSessionStartInput();
      const result = syncSessionDispatcher(input);

      expect(result.continue).toBe(true);
    });

    it('does not include suppressOutput when returning systemMessage', () => {
      vi.mocked(analyticsConsentCheck).mockReturnValue(
        makeSystemMessageResult('Consent.'),
      );

      const input = createSessionStartInput();
      const result = syncSessionDispatcher(input);

      // systemMessage path returns { continue, systemMessage } — suppressOutput should not be set
      expect(result.suppressOutput).toBeUndefined();
    });
  });

  // -------------------------------------------------------------------------
  // additionalContext fallback (mcp-health-check uses outputWithContext)
  // -------------------------------------------------------------------------

  describe('additionalContext fallback conversion', () => {
    it('converts additionalContext to systemMessage when hook has no systemMessage', () => {
      vi.mocked(mcpHealthCheck).mockReturnValue(
        makeContextResult('MCP misconfiguration: tavily missing API key.'),
      );

      const input = createSessionStartInput();
      const result = syncSessionDispatcher(input);

      expect(result.systemMessage).toContain('MCP misconfiguration');
    });

    it('does not double-count when hook has both systemMessage and context (systemMessage wins)', () => {
      // If a hook returns both systemMessage AND additionalContext,
      // only systemMessage should be collected (the code checks result.systemMessage first)
      vi.mocked(prefillGuard).mockReturnValue({
        continue: true,
        systemMessage: 'Prefill warning.',
        hookSpecificOutput: { additionalContext: 'Extra context.' } as never,
      });

      const input = createSessionStartInput();
      const result = syncSessionDispatcher(input);

      // systemMessage should appear once, not duplicated
      const count = (result.systemMessage ?? '').split('Prefill warning.').length - 1;
      expect(count).toBe(1);
    });
  });

  // -------------------------------------------------------------------------
  // Rules materialization
  // -------------------------------------------------------------------------

  describe('rules materialization', () => {
    it('calls materializeAntipatternRules at session start', () => {
      const input = createSessionStartInput({ project_dir: '/my/project' });
      syncSessionDispatcher(input);

      expect(materializeAntipatternRules).toHaveBeenCalledWith('/my/project');
    });

    it('uses getProjectDir when project_dir not in input', () => {
      const input = createSessionStartInput({ project_dir: undefined });
      syncSessionDispatcher(input);

      expect(materializeAntipatternRules).toHaveBeenCalledWith('/test/project');
    });

    it('continues even if materializeAntipatternRules throws', () => {
      vi.mocked(materializeAntipatternRules).mockImplementation(() => {
        throw new Error('rules file write failed');
      });

      const input = createSessionStartInput();
      expect(() => syncSessionDispatcher(input)).not.toThrow();
    });

    it('logs warning when rules materialization fails', () => {
      vi.mocked(materializeAntipatternRules).mockImplementation(() => {
        throw new Error('disk full');
      });

      const input = createSessionStartInput();
      syncSessionDispatcher(input);

      expect(logHook).toHaveBeenCalledWith(
        'sync-session-dispatcher',
        expect.stringContaining('materialization failed'),
        'warn',
      );
    });
  });

  // -------------------------------------------------------------------------
  // Error isolation per hook
  // -------------------------------------------------------------------------

  describe('error isolation', () => {
    it('continues when analytics-consent-check throws', () => {
      vi.mocked(analyticsConsentCheck).mockImplementation(() => {
        throw new Error('analytics crash');
      });

      const input = createSessionStartInput();
      expect(() => syncSessionDispatcher(input)).not.toThrow();
    });

    it('still calls subsequent hooks after one throws', () => {
      vi.mocked(analyticsConsentCheck).mockImplementation(() => {
        throw new Error('crash');
      });

      const input = createSessionStartInput();
      syncSessionDispatcher(input);

      expect(prefillGuard).toHaveBeenCalled();
      expect(mcpHealthCheck).toHaveBeenCalled();
    });

    it('collects messages from passing hooks even when one throws', () => {
      vi.mocked(analyticsConsentCheck).mockImplementation(() => {
        throw new Error('crash');
      });
      vi.mocked(prefillGuard).mockReturnValue(
        makeSystemMessageResult('Prefill warning survived.'),
      );

      const input = createSessionStartInput();
      const result = syncSessionDispatcher(input);

      expect(result.systemMessage).toContain('Prefill warning survived.');
    });

    it('logs warning for each failed hook', () => {
      vi.mocked(mcpHealthCheck).mockImplementation(() => {
        throw new Error('mcp crash');
      });

      const input = createSessionStartInput();
      syncSessionDispatcher(input);

      expect(logHook).toHaveBeenCalledWith(
        'sync-session-dispatcher',
        expect.stringContaining('mcp-health-check failed'),
        'warn',
      );
    });
  });

  // -------------------------------------------------------------------------
  // Plugin root injection (#961)
  // -------------------------------------------------------------------------

  describe('plugin root injection', () => {
    it('injects CLAUDE_PLUGIN_ROOT into systemMessage when plugin_root is set', () => {
      const input = createSessionStartInput({ plugin_root: '/path/to/plugin' } as Partial<HookInput>);
      const result = syncSessionDispatcher(input);

      expect(result.systemMessage).toContain('CLAUDE_PLUGIN_ROOT=/path/to/plugin');
    });

    it('does not inject when plugin_root is absent', () => {
      const input = createSessionStartInput();
      const result = syncSessionDispatcher(input);

      expect(result.systemMessage ?? '').not.toContain('CLAUDE_PLUGIN_ROOT');
    });
  });

  // -------------------------------------------------------------------------
  // Logging
  // -------------------------------------------------------------------------

  describe('logging', () => {
    it('logs "All sync hooks silent" when no messages collected', () => {
      const input = createSessionStartInput();
      syncSessionDispatcher(input);

      const calls = vi.mocked(logHook).mock.calls;
      const hasSilentLog = calls.some(
        ([name, msg]) => name === 'sync-session-dispatcher' && String(msg).includes('silent'),
      );
      expect(hasSilentLog).toBe(true);
    });

    it('logs merged count when messages are collected', () => {
      vi.mocked(analyticsConsentCheck).mockReturnValue(
        makeSystemMessageResult('Msg1'),
      );
      vi.mocked(prefillGuard).mockReturnValue(
        makeSystemMessageResult('Msg2'),
      );

      const input = createSessionStartInput();
      syncSessionDispatcher(input);

      const calls = vi.mocked(logHook).mock.calls;
      const hasMergedLog = calls.some(
        ([name, msg]) => name === 'sync-session-dispatcher' && String(msg).includes('Merged'),
      );
      expect(hasMergedLog).toBe(true);
    });
  });

  // ---------------------------------------------------------------------------
  // SessionStart perf measurement
  // ---------------------------------------------------------------------------

  describe('perf measurement', () => {
    it('records session start duration to analytics', () => {
      syncSessionDispatcher(createSessionStartInput());
      expect(appendAnalytics).toHaveBeenCalledWith('session-start-perf.jsonl', expect.objectContaining({
        duration_ms: expect.any(Number),
        hooks_fired: 3,
      }));
    });

    it('includes hashed project ID and timestamp', () => {
      syncSessionDispatcher(createSessionStartInput());
      expect(appendAnalytics).toHaveBeenCalledWith('session-start-perf.jsonl', expect.objectContaining({
        pid: 'test_hash',
        ts: expect.any(String),
      }));
    });

    it('analytics failure does not crash the dispatcher', () => {
      vi.mocked(appendAnalytics).mockImplementation(() => { throw new Error('disk full'); });
      expect(() => syncSessionDispatcher(createSessionStartInput())).not.toThrow();
    });
  });
});
